int main() {
  int T, N, X, M, i, ans;
  scanf("%d", &T);
  while (T--) {
    scanf("%d %d %d", &N, &X, &M);
    ans = 0;
    for (i = 0; i <= N; i++) {
      if ((i & 1) == 0) {
        ans = (ans + (1LL << (N - i))) % 998244353;
      }
    }
    ans = (ans * (1LL << (N % 2))) % 998244353;
    if (ans % M == X) {
      printf("%d\n", ans);
    } else {
      printf("-1\n");
    }
  }
  return 0;
}

