const readline = require('readline').createInterface({
  input: process.stdin,
  output: process.stdout
});
let input = [];
readline.on('line', line => {
  input.push(line);
});
readline.on('close', () => {
  let T = parseInt(input.shift());
  for (let i = 0; i < T; i++) {
    let [N, X, M] = input.shift().split(' ').map(Number);
    let ans = 0;
    for (let j = 0; j <= N; j++) {
      if (j & 1 == 0) {
        ans = (ans + (1 << (N - j)) % 998244353) % 998244353;
      }
    }
    ans = (ans * (1 << (N % 2)) % 998244353);
    if (ans % M == X) {
      console.log(ans);
    } else {
      console.log(-1);
    }
  }
})

